import {
  Directive,
  input,
  inject,
  DestroyRef,
  signal,
  effect,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { FormGroup } from '@angular/forms';
import { Observable } from 'rxjs';

import {
  AccountsService,
  EntitiesService,
  DistributorResponse,
} from '../../../../api';
import {
  FormFieldConfig,
  GridColumn,
  FormAction,
  BaseEntity,
} from '../../../../shared/models';
import { AdminStateService } from '../../services/admin-state.service';
import { isDefined } from '../../../../shared/utils';
import { BroadcastEventMessageService } from '../../services/broadcast-event-messages.service';

/**
 * Base component for entity settings forms
 */
@Directive()
export abstract class EntitySettingsBase<
  T extends { id: string; owner?: { id: string } },
> {
  entity = input<T | null>();
  readonly entityType = input<string>('');

  protected readonly accountsService = inject(AccountsService);
  protected readonly entitiesService = inject(EntitiesService);
  protected readonly adminState = inject(AdminStateService);
  protected readonly destroyRef = inject(DestroyRef);
  protected readonly selectOptionsLoaded = signal<boolean>(false);
  protected readonly isFormEditable = signal<boolean>(false);
  protected readonly isSubmitting = signal<boolean>(false);
  protected readonly errorMessage = signal<string | null>(null);
  protected readonly broadcastService = inject(BroadcastEventMessageService);

  formFields: FormFieldConfig[] = [];
  selectOptions: Record<string, { label: string; value: string }[]> = {};

  // Abstract properties
  protected abstract readonly columns: GridColumn[];
  protected abstract readonly actions: FormAction[];

  constructor() {
    effect(() => {
      const entityDetails = this.entity();
      const distributorDetails = this.getDistributorDetails();
      if (entityDetails && distributorDetails) {
        this.loadSelectOptions(distributorDetails);
      }
    });
  }

  /**
   * Get distributor details - can be overridden by child classes
   */
  protected getDistributorDetails(): DistributorResponse | null {
    return null;
  }

  /**
   * Load select options for the form
   */
  protected abstract loadSelectOptions(
    distributor: DistributorResponse | null,
  ): void;

  /**
   * Update form fields based on entity and loaded options
   */
  protected abstract updateFormFields(): void;

  /**
   * Helper to create a unique set of options from multiple sources
   */
  protected createUniqueOptions<
    T extends { id: string; name?: string | null },
    U extends { id: string; name?: string | null },
  >(items: T[], additionalItems: U[] = []): { label: string; value: string }[] {
    const uniqueMap = new Map<string, { id: string; name?: string | null }>();

    items.forEach((item) => {
      if (isDefined(item) && item.id) {
        uniqueMap.set(item.id, item);
      }
    });

    additionalItems.forEach((item) => {
      if (isDefined(item) && item.id) {
        uniqueMap.set(item.id, item);
      }
    });

    return Array.from(uniqueMap.values())
      .map((item) => ({
        label: item.name ?? '',
        value: item.id,
      }))
      .sort((a, b) => a.label.localeCompare(b.label));
  }

  /**
   * Extract dirty values from form
   */
  protected getDirtyValues(group: FormGroup): Record<string, string> {
    return Object.fromEntries(
      Object.entries(group.controls)
        .filter(([_, control]) => control.dirty)
        .map(([key, control]) => [key, control.value]),
    );
  }

  /**
   * Submit form data to API
   */
  onSubmit(formGroup: FormGroup): void {
    if (!this.entity()) return;

    this.isSubmitting.set(true);
    this.errorMessage.set(null);

    const dirtyValues = this.getDirtyValues(formGroup);

    if (Object.keys(dirtyValues).length === 0) {
      this.isFormEditable.set(false);
      this.isSubmitting.set(false);
      return;
    }

    this.submitChanges(dirtyValues)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response) => {
          this.isFormEditable.set(false);
          this.isSubmitting.set(false);
          this.broadcastService.broadcast('entity-updated', {
            entityType: this.entityType(),
            operation: 'update',
            entityId: (this.entity() as BaseEntity).id,
            data: response,
          });
        },
        error: () => {
          this.errorMessage.set('Failed to update settings');
          this.isSubmitting.set(false);
        },
      });
  }

  /**
   * Method to be implemented by child classes for actual API submission
   */
  protected abstract submitChanges(
    dirtyValues: Record<string, string>,
  ): Observable<T>;

  /**
   * Enters edit mode
   */
  onEdit(): void {
    this.isFormEditable.set(true);
  }
}
