import {
  Component,
  computed,
  effect,
  inject,
  OnInit,
  signal,
} from '@angular/core';

import {
  AccountsService,
  DistributorResponse,
  EntitiesService,
} from '../../../../../../api';
import { GridComponent } from '../../../../../../shared/components/grid/grid.component';
import { createDropdownField } from '../../../../../../shared/models/form-field.model';
import { DynamicFormComponent } from '../../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { FormGroup } from '@angular/forms';
import { UtilityService } from '../../../../../../core/services/utility.service';
import {
  DEFAULT_EMAIL_PROVIDER,
  DEFAULT_LIST_SIZE,
} from '../../../../../../core/models';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import {
  hasProperty,
  isDefined,
  isNullOrUndefined,
  isString,
} from '../../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../../base';

@Component({
  selector: 'app-distributor-notification-settings',
  imports: [GridComponent, DynamicFormComponent],
  templateUrl: './distributor-notification-settings.component.html',
  styleUrl: './distributor-notification-settings.component.scss',
})
export class DistributorNotificationSettingsComponent
  extends EntitySectionBaseComponent<DistributorResponse>
  implements OnInit
{
  private readonly entitiesService = inject(EntitiesService);
  private readonly accountsService = inject(AccountsService);
  private readonly utilityService = inject(UtilityService);
  protected readonly emailProvidersLoaded = signal<boolean>(false);
  emailProviders: { label: string; value: string }[] = [
    { label: DEFAULT_EMAIL_PROVIDER.name, value: DEFAULT_EMAIL_PROVIDER.id },
  ];
  readonly distributorDetails = computed(() => {
    const distributorDetails = this.entity();
    if (!isDefined(distributorDetails)) return [];

    const emailProvider = distributorDetails.emailProvider;
    const providerName =
      isDefined(emailProvider) &&
      hasProperty(emailProvider, 'name') &&
      isString(emailProvider.name)
        ? emailProvider.name
        : 'None';

    return [
      {
        key: 'Default Email Provider',
        value: providerName,
      },
    ];
  });

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    // Configure form actions
    this.actions = [
      {
        label: 'Cancel',
        action: () => this.isFormEditable.set(false),
        severity: 'secondary',
      },
      {
        label: 'Save',
        action: (formData: FormGroup) => {
          this.onSubmit(formData);
        },
        severity: 'primary',
        disabled: (form?: FormGroup) =>
          isNullOrUndefined(form) || form.pristine,
      },
    ];

    // React to entity changes
    effect(() => {
      const distributorDetails = this.entity();
      if (distributorDetails && this.emailProvidersLoaded()) {
        this.updateFormFields();
      }
    });
  }

  ngOnInit() {
    this.fetchEmailProviders();
  }

  private fetchEmailProviders() {
    const distributor = this.entity();
    if (!isDefined(distributor) || !isString(distributor.id)) {
      return;
    }

    const filters = { state: { value: 'active', operator: '=' } };
    const rqlFilter = this.utilityService.constructRqlFilter(filters);

    this.entitiesService
      .listEmailProviders(
        distributor.id,
        0,
        DEFAULT_LIST_SIZE,
        'name',
        rqlFilter,
      )
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response) => {
          if (!isDefined(response) || !hasProperty(response, 'items')) {
            return;
          }

          const providers = response.items
            .filter(
              (provider) =>
                isDefined(provider) &&
                hasProperty(provider, 'id') &&
                hasProperty(provider, 'name'),
            )
            .map((provider) => ({
              label: isString(provider.name) ? provider.name : 'Unknown',
              value: provider.id,
            }));

          this.emailProviders = [...this.emailProviders, ...providers];
          this.emailProvidersLoaded.set(true);
        },
        error: () => {
          this.emailProvidersLoaded.set(false);
        },
      });
  }

  protected override updateFormFields(): void {
    this.formFields = [
      createDropdownField(
        'emailProvider',
        'Email Provider',
        this.emailProviders,
        this.entity()?.emailProvider?.id,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'emailProvider',
          props: {
            appendTo: 'body',
          },
        },
      ),
    ];
  }

  protected override submitChanges(
    formData: Record<string, string | number>,
  ): void {
    const distributor = this.entity();
    if (isNullOrUndefined(distributor)) return;

    this.accountsService
      .updateDistributorDetails(distributor.id, formData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: () => {
          this.isFormEditable.set(false);
        },
        error: () => {
          this.isFormEditable.set(true);
        },
      });
  }
}
