import {
  Component,
  input,
  TemplateRef,
  output,
  ContentChild,
} from '@angular/core';
import { FormGroup } from '@angular/forms';
import { CommonModule } from '@angular/common';

import { ButtonModule } from 'primeng/button';
import { DialogModule } from 'primeng/dialog';

import {
  FormFieldConfig,
  FormAction,
  FormTemplateContext,
} from '../../../models/form-field.model';
import { DynamicFormComponent } from '../dynamic-form/dynamic-form.component';

@Component({
  selector: 'app-dynamic-form-modal',
  imports: [DialogModule, ButtonModule, DynamicFormComponent, CommonModule],
  templateUrl: './dynamic-form-modal.component.html',
  styleUrl: './dynamic-form-modal.component.scss',
})
export class DynamicFormModalComponent {
  @ContentChild('formHeader') formHeaderContent: TemplateRef<unknown> | null =
    null;
  visible = input<boolean>(false);
  header = input<string>('');
  fields = input<FormFieldConfig[]>([]);
  actions = input<FormAction[]>([]);
  sections = input<{ key: string; title: string; fields: FormFieldConfig[] }[]>(
    [],
  );
  templates = input<Record<string, TemplateRef<FormTemplateContext>>>({});
  styleClass = input<string>('');

  readonly modalClose = output<void>();
  readonly formSubmit = output<FormGroup>();

  private form?: FormGroup;
  /**
   * Handles the form ready event and sets the form instance.
   * @param form The form group instance.
   */
  handleFormReady(form: FormGroup): void {
    this.form = form;
  }

  /**
   * Determines if an action is visible.
   * @param action The form action.
   * @returns True if the action is visible, otherwise false.
   */
  isVisible(action: FormAction): boolean {
    if (typeof action.visible === 'function') {
      return action.visible(this.form);
    }
    return action.visible ?? true;
  }

  /**
   * Determines if an action is disabled.
   * @param action The form action.
   * @returns True if the action is disabled, otherwise false.
   */
  isDisabled(action: FormAction): boolean {
    if (typeof action.disabled === 'function') {
      return action.disabled(this.form);
    }
    return action.disabled ?? false;
  }

  /**
   * Handles form actions.
   * @param action The form action.
   */
  handleAction(action: FormAction): void {
    if (this.form && action.action) {
      action.action(this.form);
    }
  }

  /**
   * Handles the modal hide event.
   */
  onHide(): void {
    this.modalClose.emit();
    this.form?.reset();
  }

  /**
   * Track by function for actions.
   * @param index The index of the action.
   * @param action The form action.
   * @returns The label of the action.
   */
  trackByLabel(index: number, action: FormAction): string {
    return action.label;
  }
}
