import {
  AfterViewInit,
  ChangeDetectorRef,
  Component,
  computed,
  inject,
  input,
  TemplateRef,
  ViewChild,
} from '@angular/core';

import { DistributorResponse } from '../../../../../../api';
import { GridColumn } from '../../../../../../shared/models';
import { GridComponent } from '../../../../../../shared/components/grid/grid.component';
import { EntitySection } from '../../../../models';

@Component({
  selector: 'app-distributor-ssl-certificates',
  imports: [GridComponent],
  templateUrl: './distributor-ssl-certificates.component.html',
  styleUrl: './distributor-ssl-certificates.component.scss',
})
export class DistributorSslCertificatesComponent
  implements AfterViewInit, EntitySection<DistributorResponse>
{
  @ViewChild('sslCertificatesTemplate', { static: true })
  sslCertificatesTemplate: TemplateRef<unknown> | undefined;
  private readonly cdr = inject(ChangeDetectorRef);

  entity = input<DistributorResponse | null>();
  readonly distributorDetails = computed(() => {
    const details = this.entity();
    if (!details) return [];

    return [
      {
        key: 'Domains',
        value: details?.sslCertificates || [],
      },
    ];
  });
  columns: GridColumn[] = [];

  ngAfterViewInit(): void {
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      {
        field: 'value',
        header: '',
        cellTemplate: this.sslCertificatesTemplate,
      },
    ];
    this.cdr.detectChanges();
  }
}
