import {
  Component,
  computed,
  DestroyRef,
  effect,
  inject,
  input,
  signal,
  TemplateRef,
  ViewChild,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormGroup } from '@angular/forms';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

import {
  createDropdownField,
  FormAction,
  FormFieldConfig,
  GroupValues,
} from '../../../../../../shared/models/form-field.model';
import { DistributorResponse, ThemeListItem } from '../../../../../../api';
import { DynamicFormComponent } from '../../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../../shared/components/grid/grid.component';
import { GridColumn } from '../../../../../../shared/models';
import { ApiUrlService } from '../../../../../../core/services/api-url.service';
import { UtilsService } from '../../../../../../shared/services/utils.service';
import { LogoTemplateContext } from '../../../../models/templates.interface';
import { finalize } from 'rxjs';
import { DistributorCustomizationService } from '../../../../services/distributor-customization.service';
import { ImageEditorComponent } from '../../../../../../shared/components/image-editor/image-editor.component';
import {
  hasProperty,
  isDefined,
  isString,
} from '../../../../../../shared/utils';

@Component({
  selector: 'app-customize-distributor',
  imports: [
    CommonModule,
    DynamicFormComponent,
    GridComponent,
    ImageEditorComponent,
  ],
  templateUrl: './customize-distributor.component.html',
  styleUrl: './customize-distributor.component.scss',
})
export class CustomizeDistributorComponent {
  @ViewChild('customTemplate', { static: true }) logoTemplate:
    | TemplateRef<LogoTemplateContext>
    | undefined;
  entity = input<DistributorResponse | null>();

  private readonly customizationService = inject(
    DistributorCustomizationService,
  );
  private readonly utilsService = inject(UtilsService);

  private readonly apiUrlService = inject(ApiUrlService);
  private readonly destroyRef = inject(DestroyRef);
  protected readonly isFormEditable = signal<boolean>(false);
  protected readonly isSubmitting = signal<boolean>(false);
  readonly columns = signal<GridColumn[]>([]);

  readonly distributorDetails = computed(() => {
    const details = this.entity();
    if (!isDefined(details)) return [];

    const apiUrl = this.apiUrlService.getCurrentApiUrl();
    if (!isString(apiUrl) || !isString(details.id)) {
      console.warn('Invalid API URL or distributor ID');
      return [];
    }

    return [
      {
        key: 'Logo',
        value: '',
        imageUrl: `${apiUrl}/accounts/distributors/${details.id}/logo?size=large`,
        imageCaption:
          'The image will be resampled to 800 x 333 pixels and will be used on reports.',
      },
      {
        key: 'Web Logo',
        value: '',
        imageUrl: `${apiUrl}/accounts/distributors/${details.id}/logo?size=small`,
        imageCaption:
          'The image will be resampled to 240 x 100 pixels. For better results you should pre-scale your image in a graphics program before uploading.',
      },
      {
        key: 'Language',
        value: isDefined(details.language)
          ? this.getLanguageName(details.language)
          : 'None',
      },
      {
        key: 'Theme',
        value:
          isDefined(details.theme) && hasProperty(details.theme, 'name')
            ? details.theme.name
            : 'None',
      },
    ];
  });
  readonly languages = this.utilsService.getLanguages();
  formFields: FormFieldConfig[] = [];
  themes: ThemeListItem[] = [];
  isImageEditorVisible = false;

  actions: FormAction[] = [
    {
      label: 'Cancel',
      action: () => this.isFormEditable.set(false),
      severity: 'secondary',
    },
    {
      label: 'Save',
      action: (formData: FormGroup) => {
        this.onSubmit(formData);
      },
      severity: 'primary',
      disabled: (form?: FormGroup) => !isDefined(form) || form.pristine,
    },
  ];
  file: string | undefined;

  constructor() {
    effect(() => {
      const distributor = this.entity();
      if (distributor) {
        this.customizationService
          .getThemes(distributor.id)
          .pipe(takeUntilDestroyed(this.destroyRef))
          .subscribe({
            next: (themes) => {
              this.themes = themes;
              this.updateFormFields();
            },
          });
      }
    });

    effect(() => {
      if (this.logoTemplate) {
        this.columns.set([
          { field: 'key', header: '', transform: 'uppercase' },
          { field: 'value', header: '', cellTemplate: this.logoTemplate },
        ]);
      }
    });
  }

  private getLanguageName(languageId: string): string {
    const language = this.languages.find(
      (lang) =>
        isDefined(lang) && hasProperty(lang, 'id') && lang.id === languageId,
    );

    return isDefined(language) && hasProperty(language, 'name')
      ? language.name
      : 'None';
  }

  private getDirtyValues(group: FormGroup): GroupValues {
    if (!isDefined(group)) return {};

    const dirtyValues: GroupValues = Object.fromEntries(
      Object.entries(group.controls)
        .filter(([_, control]) => isDefined(control) && control.dirty)
        .map(([key, control]) => [
          key,
          control.value as string | number | boolean | null,
        ]),
    );

    if (hasProperty(dirtyValues, 'theme')) {
      const selectedTheme = this.themes.find(
        (theme) =>
          isDefined(theme) &&
          hasProperty(theme, 'id') &&
          theme.id === dirtyValues['theme'],
      );

      dirtyValues['theme'] = isDefined(selectedTheme)
        ? selectedTheme.id
        : 'inherited';
    }

    return dirtyValues;
  }

  private updateFormFields(): void {
    this.formFields = [
      createDropdownField(
        'language',
        'Language',
        this.languages.map((lang) => ({
          label: lang.name,
          value: lang.id,
        })),
        this.entity()?.language,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          placeholder: 'Select language',
          name: 'language',
          props: {
            // Using 'body' to ensure proper overlay positioning and width
            // Alternative approaches with container elements can cause positioning issues
            appendTo: 'body',
          },
        },
      ),
      createDropdownField(
        'theme',
        'Theme',
        [{ label: 'Inherited', value: 'inherited' }].concat(
          this.themes.map((theme) => ({
            label: theme.name,
            value: theme.id,
          })),
        ),
        this.entity()?.theme?.id,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          placeholder: 'Select theme',
          name: 'theme',
          props: {
            appendTo: 'body',
          },
        },
      ),
    ];
  }

  onSubmit(formGroup: FormGroup): void {
    const currentDistributor = this.entity();
    if (!currentDistributor) return;

    this.isSubmitting.set(true);

    const dirtyValues = this.getDirtyValues(formGroup);
    if (Object.keys(dirtyValues).length === 0) {
      this.isFormEditable.set(false);
      this.isSubmitting.set(false);
      return;
    }

    this.customizationService
      .updateDistributorDetails(currentDistributor.id, dirtyValues)
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        finalize(() => this.isSubmitting.set(false)),
      )
      .subscribe({
        next: () => this.isFormEditable.set(false),
        error: () => this.isFormEditable.set(true),
      });
  }

  onEdit() {
    this.isFormEditable.set(true);
  }

  onImageEditorVisibleChange(visible: boolean, file?: string): void {
    this.isImageEditorVisible = visible;
    this.file = file;
  }

  saveFile(file: File): void {
    if (!this.entity()) return;

    this.isSubmitting.set(true);

    const formData = new FormData();
    formData.append('logo', file);
  }

  updateLogo() {
    // To be implemented when formData is added to the API
    return;
  }
}
