import { HttpClient } from '@angular/common/http';
import {
  Directive,
  OnInit,
  input,
  inject,
  DestroyRef,
  signal,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { Validators, FormGroup } from '@angular/forms';

import { AccountsService, CompanyAddress } from '../../../../api';
import {
  FormFieldConfig,
  GridColumn,
  FormAction,
  createTextField,
  createDropdownField,
} from '../../../../shared/models';
import { Observable } from 'rxjs';
import { hasProperty, isDefined, isString } from '../../../../shared/utils';

/**
 * Base component for entity address forms (clients, vendors, distributors)
 */
@Directive()
export abstract class EntityAddressComponent<
  T extends { id: string; address?: CompanyAddress },
> implements OnInit
{
  entity = input<T | null>();

  protected readonly http = inject(HttpClient);
  protected readonly accountsService = inject(AccountsService);
  protected readonly destroyRef = inject(DestroyRef);
  protected readonly isFormEditable = signal<boolean>(false);
  protected readonly isSubmitting = signal<boolean>(false);
  protected readonly countriesLoaded = signal<boolean>(false);
  protected readonly errorMessage = signal<string | null>(null);

  formFields: FormFieldConfig[] = [];
  countries: { label: string; value: string }[] = [];
  readonly columns: GridColumn[] = [
    { field: 'key', header: '', transform: 'uppercase' },
    { field: 'value', header: '' },
  ];

  // Abstract properties
  protected abstract readonly actions: FormAction[];

  ngOnInit(): void {
    this.loadCountries();
  }

  /**
   * Loads countries from JSON file
   */
  protected loadCountries(): void {
    this.http
      .get<Record<string, string>>('/assets/docs/countries.json')
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (data) => {
          this.countries = Object.entries(data)
            .map(([key, value]) => ({
              label: value,
              value: key,
            }))
            .sort((a, b) => a.label.localeCompare(b.label));

          this.countriesLoaded.set(true);
          this.updateFormFields();
        },
        error: (error) => {
          console.error('Failed to load countries', error);
          this.errorMessage.set('Failed to load countries');
          this.countriesLoaded.set(true);
        },
      });
  }

  /**
   * Creates standard address form fields
   */
  protected updateFormFields(): void {
    const address = this.entity()?.address || {};

    this.formFields = [
      createTextField('address', 'Address', address.address, {
        name: 'address',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Address is required',
          },
        ],
      }),
      createTextField('city', 'City', address.city, {
        name: 'city',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'City is required',
          },
        ],
      }),
      createTextField('state', 'State', address.state, {
        name: 'state',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'State is required',
          },
        ],
      }),
      createTextField('code', 'Code', address.code, {
        name: 'code',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Code is required',
          },
        ],
      }),
      createDropdownField(
        'country',
        'Country',
        this.countries,
        address.country,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          placeholder: 'Select country',
          name: 'country',
          props: { appendTo: 'body' },
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: 'Country is required',
            },
          ],
        },
      ),
    ];
  }

  /**
   * Extract dirty values from form
   */
  protected getDirtyValues(group: FormGroup): Record<string, string> {
    return Object.fromEntries(
      Object.entries(group.controls)
        .filter(([_, control]) => control.dirty)
        .map(([key, control]) => [key, control.value]),
    );
  }

  /**
   * Submit form data to API
   */
  onSubmit(formGroup: FormGroup): void {
    if (!this.entity()) return;

    this.isSubmitting.set(true);
    this.errorMessage.set(null);

    const dirtyValues = this.getDirtyValues(formGroup);

    if (Object.keys(dirtyValues).length === 0) {
      this.isFormEditable.set(false);
      this.isSubmitting.set(false);
      return;
    }

    this.submitChanges({ address: dirtyValues })
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: () => {
          this.isFormEditable.set(false);
          this.isSubmitting.set(false);
        },
        error: () => {
          this.errorMessage.set('Failed to update address');
          this.isSubmitting.set(false);
        },
      });
  }

  /**
   * Method to be implemented by child classes for actual API submission
   */
  protected abstract submitChanges(addressData: {
    address: Record<string, string>;
  }): Observable<T>;

  /**
   * Enters edit mode
   */
  onEdit(): void {
    this.isFormEditable.set(true);
  }

  findCountryLabel(countryCode?: string | null): string {
    if (!isString(countryCode)) return 'None';

    const country = this.countries.find(
      (country) =>
        isDefined(country) &&
        hasProperty(country, 'value') &&
        country.value === countryCode,
    );

    return isDefined(country) && hasProperty(country, 'label')
      ? country.label
      : 'None';
  }
}
