import { Component, computed } from '@angular/core';
import { EMPTY } from 'rxjs';

import { DistributorResponse } from '../../../../../../api';
import { GridComponent } from '../../../../../../shared/components/grid/grid.component';
import { FormAction, GridColumn } from '../../../../../../shared/models';
import {
  hasProperty,
  isArray,
  isDefined,
} from '../../../../../../shared/utils';
import { EntitySettingsBase } from '../../../base';

@Component({
  selector: 'app-distributor-settings',
  imports: [GridComponent],
  templateUrl: './distributor-settings.component.html',
  styleUrl: './distributor-settings.component.scss',
})
export class DistributorSettingsComponent extends EntitySettingsBase<DistributorResponse> {
  readonly distributorDetails = computed(() => {
    const distributorDetails = this.entity();
    if (!isDefined(distributorDetails)) return [];

    const emailProviders = distributorDetails.availableEmailProviders;
    const mapSets = distributorDetails.availableMapSets;

    return [
      {
        key: 'Available Email providers',
        value:
          isArray(emailProviders) && emailProviders.length > 0
            ? emailProviders
                .filter(
                  (provider) =>
                    isDefined(provider) && hasProperty(provider, 'name'),
                )
                .map((provider) => provider.name)
                .join(', ')
            : 'None',
      },
      {
        key: 'Available Map Sets',
        value:
          isArray(mapSets) && mapSets.length > 0
            ? mapSets
                .filter(
                  (mapSet) => isDefined(mapSet) && hasProperty(mapSet, 'name'),
                )
                .map((mapSet) => mapSet.name)
                .join(', ')
            : 'None',
      },
    ];
  });

  readonly columns: GridColumn[] = [
    { field: 'key', header: '', transform: 'uppercase' },
    { field: 'value', header: '' },
  ];

  protected readonly actions: FormAction[] = [];

  protected updateFormFields(): void {
    // No form fields to update
  }

  protected override submitChanges(_dirtyValues: Record<string, string>) {
    // No changes to submit
    return EMPTY;
  }

  protected override loadSelectOptions(
    _distributor: DistributorResponse | null,
  ): void {
    // No select options to load
  }
}
