import { Component, computed } from '@angular/core';
import { GridComponent } from '../../../../../../shared/components/grid/grid.component';
import { FormAction, GridColumn } from '../../../../../../shared/models';
import { DistributorResponse } from '../../../../../../api';
import { isArray, isDefined, isString } from '../../../../../../shared/utils';
import { EntityDetailsBase } from '../../../base';
import { EMPTY } from 'rxjs';

@Component({
  selector: 'app-distributor-details',
  imports: [GridComponent],
  templateUrl: './distributor-details.component.html',
  styleUrl: './distributor-details.component.scss',
})
export class DistributorDetailsComponent extends EntityDetailsBase<DistributorResponse> {
  readonly distributorDetails = computed(() => {
    const distributorDetails = this.entity();
    if (!isDefined(distributorDetails)) return [];

    return [
      {
        key: 'Name',
        value: isString(distributorDetails.name)
          ? distributorDetails.name
          : 'N/A',
      },
      {
        key: 'Website',
        value: isString(distributorDetails.website)
          ? distributorDetails.website
          : 'N/A',
      },
      {
        key: 'Tags',
        value:
          isArray(distributorDetails.tags) && distributorDetails.tags.length > 0
            ? distributorDetails.tags.filter(isString).join(', ')
            : 'None',
      },
    ];
  });
  readonly columns: GridColumn[] = [
    { field: 'key', header: '', transform: 'uppercase' },
    { field: 'value', header: '' },
  ];

  protected readonly actions: FormAction[] = [];

  protected updateFormFields(): void {
    // No form fields to update
  }

  protected override submitChanges(_dirtyValues: Record<string, string>) {
    // No changes to submit
    return EMPTY;
  }
}
