import { Directive, input, inject, DestroyRef, signal } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { FormGroup } from '@angular/forms';
import { catchError, Observable, of } from 'rxjs';

import { AccountsService } from '../../../../api';
import { GridColumn } from '../../../../shared/models';
import {
  FormFieldConfig,
  FormAction,
} from '../../../../shared/models/form-field.model';

/**
 * Base component for entity detail forms (clients, vendors, distributors)
 */
@Directive()
export abstract class EntityDetailsBase<T extends { id: string }> {
  entity = input<T | null>();

  protected readonly accountsService = inject(AccountsService);
  protected readonly destroyRef = inject(DestroyRef);
  protected readonly isFormEditable = signal<boolean>(false);
  protected readonly isSubmitting = signal<boolean>(false);
  protected readonly errorMessage = signal<string | null>(null);

  formFields: FormFieldConfig[] = [];

  // Abstract properties that must be implemented by child classes
  protected abstract readonly columns: GridColumn[];
  protected abstract readonly actions: FormAction[];

  /**
   * Initializes the form fields based on the entity data
   * Must be implemented by child classes
   */
  protected abstract updateFormFields(): void;

  /**
   * Extracts dirty values from form for submission
   */
  protected getDirtyValues(group: FormGroup): Record<string, string | number> {
    return Object.fromEntries(
      Object.entries(group.controls)
        .filter(([_, control]) => control.dirty)
        .map(([key, control]) => [key, control.value]),
    );
  }

  /**
   * Submits form changes to the API
   */
  protected onSubmit(formGroup: FormGroup): void {
    if (!this.entity()) return;

    this.isSubmitting.set(true);
    this.errorMessage.set(null);

    const dirtyValues = this.getDirtyValues(formGroup);

    if (Object.keys(dirtyValues).length === 0) {
      this.isFormEditable.set(false);
      this.isSubmitting.set(false);
      return;
    }

    this.submitChanges(dirtyValues)
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        catchError((error) => {
          this.errorMessage.set('Failed to update details');
          console.error('Update error:', error);
          return of(null);
        }),
      )
      .subscribe({
        next: () => {
          this.isFormEditable.set(false);
          this.isSubmitting.set(false);
        },
        error: () => {
          this.isSubmitting.set(false);
        },
      });
  }

  /**
   * Method to be implemented by child classes for actual API submission
   */
  protected abstract submitChanges(
    dirtyValues: Record<string, string | number>,
  ): Observable<T>;

  /**
   * Enters edit mode
   */
  onEdit(): void {
    this.isFormEditable.set(true);
  }
}
