import {
  Component,
  DestroyRef,
  ViewChild,
  computed,
  effect,
  inject,
  input,
  output,
  signal,
} from '@angular/core';
import { FormGroup } from '@angular/forms';
import { BaseEntity, GridColumn } from '../../../../shared/models';
import {
  FormAction,
  FormFieldConfig,
} from '../../../../shared/models/form-field.model';
import { MessageService } from 'primeng/api';
import { isDefined, isNullOrUndefined } from '../../../../shared/utils';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { Observable, finalize } from 'rxjs';
import { DynamicFormComponent } from '../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { BroadcastEventMessageService } from '../../services/broadcast-event-messages.service';

interface EntitySectionOptions {
  readonly?: boolean;
  title?: string;
  expanded?: boolean;
  category?: 'information' | 'settings' | 'statistics' | 'custom';
  order?: number;
}

/**
 * Base component for entity sections in the administration module.
 * Provides common functionality for displaying and editing entity details.
 */
@Component({ template: '' })
export abstract class EntitySectionBaseComponent<T> {
  @ViewChild(DynamicFormComponent) dynamicForm?: DynamicFormComponent;
  entity = input.required<T | null>();
  readonly createMode = input<boolean>(false);
  readonly entityType = input<string>('');
  readonly dataPath = input<string>('');
  readonly injectDataAtPath = input<boolean>(false);

  readonly formValidityChange = output<boolean>();
  readonly formValidity = signal<boolean>(false);
  readonly formValueChange = output<Record<string, unknown>>();
  onEntityChange = input<(entity: T) => void>(() => {});
  entityChange = output<T>();

  options = input<EntitySectionOptions>({ readonly: false });
  mode = input<'view' | 'edit'>('view');

  // Computed values based on inputs
  protected readonly entityValue = computed(() => this.entity());
  readonly isEditing = computed(
    () => this.mode() === 'edit' && (this.options()?.readonly ?? false),
  );
  readonly isViewing = computed(
    () => this.mode() === 'view' || this.options()?.readonly,
  );
  readonly sectionTitle = computed(() => this.options()?.title ?? 'Details');
  readonly sectionCategory = computed(
    () => this.options()?.category ?? 'information',
  );
  readonly sectionOrder = computed(() => this.options()?.order ?? 0);
  readonly canBeEdited = computed(() => {
    const entity = this.entity() as T & { state?: string };
    return entity?.state !== 'deleted';
  });

  // Common state management
  protected readonly isFormEditable = signal<boolean>(false);
  protected readonly isSubmitting = signal<boolean>(false);
  protected readonly isLoading = signal<boolean>(false);

  // Services
  protected readonly messageService = inject(MessageService);
  protected readonly broadcastService = inject(BroadcastEventMessageService);
  protected readonly destroyRef = inject(DestroyRef);

  // Form configuration
  protected formFields: FormFieldConfig[] = [];
  protected actions: FormAction[] = [
    {
      label: 'Cancel',
      action: () => this.isFormEditable.set(false),
      severity: 'secondary',
    },
    {
      label: 'Save',
      action: (formData: FormGroup) => {
        this.onSubmit(formData);
      },
      severity: 'primary',
      disabled: (form?: FormGroup) => isNullOrUndefined(form) || form.pristine,
      loading: () => this.isSubmitting(),
    },
  ];

  // Grid configuration
  columns: GridColumn[] = [];
  columnsSignal = signal<GridColumn[]>([]);

  // Form handling
  protected form?: FormGroup;
  protected readonly formInitialized = signal<boolean>(false);

  constructor() {
    // React to mode changes
    effect(() => {
      const isEditing = this.isEditing();
      this.isFormEditable.set(isEditing);

      if (isEditing) {
        this.onEnterEditMode();
      } else {
        this.onExitEditMode();
      }
    });

    // React to entity changes
    effect(() => {
      const entity = this.entity();
      if (isDefined(entity) && !this.formInitialized()) {
        this.onEntityLoaded(entity);
        this.formInitialized.set(true);
      }
    });

    effect(() => {
      const currentMode = this.mode();
      if (currentMode === 'edit') {
        this.onEnterEditMode();
      } else {
        this.onExitEditMode();
      }
    });
  }

  /**
   * Called when entity data is loaded
   * Override in child classes as needed
   */
  protected onEntityLoaded(_entity: T): void {
    this.updateFormFields();
  }

  /**
   * Called when entering edit mode
   * Override in child classes as needed
   */
  protected onEnterEditMode(): void {
    // Default implementation
  }

  /**
   * Called when exiting edit mode
   * Override in child classes as needed
   */
  protected onExitEditMode(): void {
    // Default implementation
  }

  /**
   * Updates form fields based on entity data
   */
  protected abstract updateFormFields(): void;

  /**
   * Submits changes to the backend
   */
  protected submitChanges(
    formData: Record<string, unknown> | Record<string, string | number>[],
  ): void {
    const entity = this.entity();
    if (isNullOrUndefined(entity)) return;

    // Transform data if needed
    const transformedData = this.transformFormData
      ? this.transformFormData(formData)
      : (formData as Partial<T>);

    // Get the update method dynamically based on entity type
    const updateMethod = this.getUpdateMethod();

    if (isNullOrUndefined(updateMethod)) {
      console.error(
        `Update method not found for entity type: ${this.entityType()}`,
      );
      return;
    }

    // Call the update method
    updateMethod((entity as BaseEntity).id, transformedData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response) => {
          this.isFormEditable.set(false);
          this.isSubmitting.set(false);
          this.broadcastService.broadcast('entity-updated', {
            entityType: this.entityType(),
            operation: 'update',
            entityId: (entity as BaseEntity).id,
            data: response,
          });
        },
        error: () => {
          this.isFormEditable.set(true);
          this.isSubmitting.set(false);
        },
      });
  }

  /**
   * Get the update method for the entity
   * Must be implemented by derived components
   */
  protected getUpdateMethod(): (
    id: string,
    data: Partial<T>,
  ) => Observable<unknown> {
    return (_id, _data) => {
      return new Observable((observer) => {
        observer.complete(); // No-op implementation
      });
    };
  }

  /**
   * Optional method for transforming form data
   * Can be overridden by derived components
   */
  protected transformFormData?(
    formData: Record<string, unknown> | Record<string, string | number>[],
  ): Partial<T> {
    return formData as Partial<T>;
  }

  /**
   * Handle form submission
   */
  protected onSubmit(formGroup: FormGroup): void {
    if (isNullOrUndefined(this.entity()) || !formGroup.valid) return;

    this.isSubmitting.set(true);

    const formData = this.getDirtyValues(formGroup);
    if (Object.keys(formData).length === 0) {
      this.isFormEditable.set(false);
      this.isSubmitting.set(false);
      return;
    }

    this.submitChanges(formData);
  }

  // Add after submitChanges method

  /**
   * Utility method to handle entity updates
   * @param updateObservable Observable that returns the updated entity
   * @param successMessage Success message to display
   */
  protected handleEntityUpdate<R>(
    updateObservable: Observable<R>,
    successMessage = 'Updated successfully',
  ): void {
    this.isSubmitting.set(true);

    updateObservable
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        finalize(() => this.isSubmitting.set(false)),
      )
      .subscribe({
        next: (response) => {
          // If response has the same shape as our entity, update it
          if (isDefined(response) && typeof response === 'object') {
            const typedResponse = response as unknown as T;

            // Emit via regular output
            this.entityChange.emit(typedResponse);

            // Also call the callback function if provided
            const callback = this.onEntityChange();
            if (typeof callback === 'function') {
              callback(typedResponse);
            }
          }
          this.isFormEditable.set(false);
          this.showSuccessMessage(successMessage);
        },
        error: (error) => {
          this.isFormEditable.set(true);
          this.showErrorMessage(error);
        },
      });
  }

  /**
   * Extract only changed form values
   */
  protected getDirtyValues(
    formGroup: FormGroup,
  ): Record<string, string | number | object> {
    const dirtyValues: Record<string, string | number | object> = {};

    Object.keys(formGroup.controls).forEach((key) => {
      const control = formGroup.controls[key];

      if (control.dirty) {
        dirtyValues[key] = control.value;
      }
    });

    return dirtyValues;
  }

  /**
   * Toggle edit mode
   */
  protected onEdit(): void {
    if (!this.canBeEdited()) {
      this.showErrorMessage(new Error('Deleted items cannot be edited.'));
      return;
    }
    this.isFormEditable.set(true);
  }

  /**
   * Show success message
   */
  protected showSuccessMessage(message: string): void {
    this.messageService.add({
      severity: 'success',
      summary: 'Success',
      detail: message,
    });
  }

  /**
   * Show error message
   */
  protected showErrorMessage(error: Error): void {
    this.messageService.add({
      severity: 'error',
      summary: 'Error',
      detail: error?.message || 'An error occurred',
    });
  }

  /**
   * Prepare display fields for view mode
   * Override in child classes as needed
   */
  protected getDisplayFields(): {
    key: string;
    value: string | number | null;
  }[] {
    return [];
  }

  /**
   * Reset form to entity values
   * Useful when canceling edits
   */
  protected resetForm(): void {
    if (this.form && isDefined(this.entity())) {
      // Default implementation - override with specific mapping in child components
      this.updateFormFields();
    }
  }

  /**
   * Check if the form is valid
   * @returns boolean indicating validity
   */
  validate(): boolean {
    if (!this.dynamicForm?.form) {
      return false;
    }

    // Mark all fields as touched to trigger validation
    this.touchAllFormControls(this.dynamicForm.form);

    // Return current validity
    const isValid = this.dynamicForm.form.valid;
    this.formValidity.set(isValid);
    return isValid;
  }

  /**
   * Get the form value from the dynamic form component
   * @returns Form value as a record of key-value pairs
   */
  getFormValue(): Record<string, unknown> {
    if (!this.dynamicForm?.form) {
      return {};
    }
    return this.dynamicForm.form.value;
  }

  /**
   * Get the form group from the dynamic form component
   * @returns FormGroup or undefined if not available
   */
  protected getFormGroup(): FormGroup | undefined {
    return this.dynamicForm?.form;
  }

  /**
   * Handle form validity changes
   * @param validity Boolean indicating form validity
   */
  protected onFormValidityChange(validity: boolean): void {
    this.formValidity.set(validity);
    this.formValidityChange.emit(validity);
  }

  /**
   * Handle form value changes
   * @param formData Form data as a record of key-value pairs
   */
  protected onFormValueChange(formData: Record<string, string | number>): void {
    this.formValueChange.emit(formData);
  }

  /**
   * Mark all form controls as touched
   * This is useful for triggering validation messages
   * @param formGroup The form group to touch
   * @private
   * @returns void
   */
  private touchAllFormControls(formGroup: FormGroup): void {
    Object.keys(formGroup.controls).forEach((key) => {
      const control = formGroup.get(key);
      if (control instanceof FormGroup) {
        this.touchAllFormControls(control);
      } else if (control) {
        control.markAsTouched();
        control.updateValueAndValidity();
      }
    });
  }
}
