import { inject, Injectable } from '@angular/core';
import { Observable, map } from 'rxjs';

import {
  AccountsService,
  DistributorDetailsUpdateRequest,
  DistributorResponse,
  ThemeListItem,
  ThemesService,
} from '../../../api';

@Injectable({
  providedIn: 'root',
})
export class DistributorCustomizationService {
  private readonly accountsService = inject(AccountsService);
  private readonly themesService = inject(ThemesService);

  getThemes(distributorId: string): Observable<ThemeListItem[]> {
    return this.themesService
      .listThemes(distributorId)
      .pipe(map((response) => response.items));
  }

  updateDistributorDetails(
    distributorId: string,
    updates: DistributorDetailsUpdateRequest,
  ): Observable<DistributorResponse> {
    return this.accountsService.updateDistributorDetails(
      distributorId,
      updates,
    );
  }
}
