import { CommonModule } from '@angular/common';
import { Component, computed, effect } from '@angular/core';

import {
  createDropdownField,
  createTextField,
  FormAction,
} from '../../../../../../shared/models/form-field.model';
import { DistributorResponse } from '../../../../../../api';
import { FormGroup, Validators } from '@angular/forms';
import { DynamicFormComponent } from '../../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../../shared/components/grid/grid.component';
import {
  isDefined,
  isNullOrUndefined,
  isString,
} from '../../../../../../shared/utils';
import { EntityAddressComponent } from '../../../base';

@Component({
  selector: 'app-distributor-address',
  imports: [DynamicFormComponent, GridComponent, CommonModule],
  templateUrl: './distributor-address.component.html',
  styleUrl: './distributor-address.component.scss',
})
export class DistributorAddressComponent extends EntityAddressComponent<DistributorResponse> {
  readonly address = computed(() => {
    const distributorDetails = this.entity();
    if (
      isNullOrUndefined(distributorDetails) ||
      isNullOrUndefined(distributorDetails.address) ||
      !this.countriesLoaded()
    )
      return [];

    const address = distributorDetails.address;

    return [
      {
        key: 'Address',
        value: isString(address.address) ? address.address : 'None',
      },
      {
        key: 'City',
        value: isString(address.city) ? address.city : 'None',
      },
      {
        key: 'State',
        value: isString(address.state) ? address.state : 'None',
      },
      {
        key: 'Code',
        value: isString(address.code) ? address.code : 'None',
      },
      {
        key: 'Country',
        value: this.findCountryLabel(address.country),
      },
    ];
  });

  actions: FormAction[] = [
    {
      label: 'Cancel',
      action: () => this.isFormEditable.set(false),
      severity: 'secondary',
    },
    {
      label: 'Save',
      action: (formData: FormGroup) => {
        this.onSubmit(formData);
      },
      severity: 'primary',
      disabled: (form?: FormGroup) => !isDefined(form) || form.pristine,
    },
  ];

  constructor() {
    super();
    effect(() => {
      const distributorDetails = this.entity();
      if (distributorDetails && this.countriesLoaded()) {
        this.updateFormFields();
      }
    });
  }

  protected override updateFormFields(): void {
    const distributor = this.entity();
    this.formFields = [
      createTextField('address', 'Address', distributor?.address?.address, {
        name: 'address',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Address is required',
          },
        ],
      }),

      createTextField('city', 'City', distributor?.address?.city, {
        name: 'city',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'City is required',
          },
        ],
      }),

      createTextField('state', 'State', distributor?.address?.state, {
        name: 'state',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'State is required',
          },
        ],
      }),

      createTextField('code', 'Code', distributor?.address?.code, {
        name: 'code',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Code is required',
          },
        ],
      }),

      createDropdownField(
        'country',
        'Country',
        this.countries,
        distributor?.address?.country,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          placeholder: 'Select country',
          name: 'country',
          props: {
            appendTo: 'body',
          },
        },
      ),
    ];
  }

  protected override submitChanges(addressData: {
    address: Record<string, string>;
  }) {
    const distributor = this.entity();
    if (!distributor) {
      throw new Error('Distributor is required');
    }
    return this.accountsService.updateDistributorDetails(distributor.id, {
      address: addressData.address,
    });
  }
}
